	// Try to create informers for all CRD types
	resources := []struct {
		name string
		gvr  schema.GroupVersionResource
	}{
		{"ServiceMonitor", monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ServiceMonitorName)},
		{"PodMonitor", monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.PodMonitorName)},
		{"Probe", monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ProbeName)},
		{"ScrapeConfig", promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName)},
	}

	for _, res := range resources {
		logger.Info("Attempting to create informer", "resource", res.name)
		informer, err := informers.NewInformersForResource(factory, res.gvr)
		if err != nil {
			logger.Error("Failed to create informer", "resource", res.name, "error", err)
		} else {
			logger.Info("Successfully created informer", "resource", res.name)

			// Try to start the informer
			stopCh := make(chan struct{})
			informer.Start(stopCh)

