			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()

			go func() {
				select {
				case <-ctx.Done():
					logger.Warn("Cache sync timeout", "resource", res.name)
					close(stopCh)
				}
			}()

			// This would fail in real cluster if CRD doesn't exist
			logger.Info("Checking if informer has synced", "resource", res.name)
			time.Sleep(100 * time.Millisecond)
		}
	}

	// Now let's test CRD existence check approach
	fmt.Println("\n=== Testing CRD existence check approach ===")

	// Simulate checking if CRDs exist (in real code, we'd use API server)
	// For this test, we'll check the fake client
	crdTypes := []schema.GroupVersionResource{
		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ServiceMonitorName),
		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.PodMonitorName),
		monitoringv1.SchemeGroupVersion.WithResource(monitoringv1.ProbeName),
		promv1alpha1.SchemeGroupVersion.WithResource(promv1alpha1.ScrapeConfigName),
	}

	for _, gvr := range crdTypes {
		// Try to list the resource to check if it exists
		_, err := mClient.Discovery().ServerResourcesForGroupVersion(gvr.GroupVersion().String())
		if err != nil {
			if errors.IsNotFound(err) {
				logger.Warn("CRD not found", "resource", gvr.Resource)
			} else {
				logger.Error("Error checking CRD", "resource", gvr.Resource, "error", err)
			}
		} else {
			logger.Info("CRD exists", "resource", gvr.Resource)
		}
	}

	fmt.Println("\nTest completed")
}

