// TestGetInformersWithMissingCRDs tests that getInformers handles missing CRDs gracefully
func TestGetInformersWithMissingCRDs(t *testing.T) {
	// Create fake clients
	mClient := fakemonitoringclient.NewSimpleClientset()

	// Create a factory
	factory := informers.NewMonitoringInformerFactories(
		map[string]struct{}{v1.NamespaceAll: {}},
		map[string]struct{}{},
