	// The function should return a map with only the available informers
	assert.NoError(t, err, "getInformers should not return an error when CRDs are missing")
	assert.NotNil(t, informerMap, "informerMap should not be nil")

	// In a fake client scenario, informers might be created but won't work properly
	// The important thing is that the code doesn't crash
}

// TestLoadConfigWithMissingCRDs tests that LoadConfig handles missing CRDs gracefully
func TestLoadConfigWithMissingCRDs(t *testing.T) {
	namespace := "test"

	// Create service monitors but not other CRD types
	serviceMonitors := []*monitoringv1.ServiceMonitor{
		{
			ObjectMeta: metav1.ObjectMeta{
				Name:      "test-sm",
				Namespace: namespace,
			},
			Spec: monitoringv1.ServiceMonitorSpec{
				JobLabel: "test",
				Endpoints: []monitoringv1.Endpoint{
					{
						Port: "web",
					},
				},
			},
		},
