// Copyright The OpenTelemetry Authors
// SPDX-License-Identifier: Apache-2.0

// This test simulates the exact scenario from the bug report:
// - ServiceMonitor and PodMonitor CRDs exist
// - Probe and ScrapeConfig CRDs do NOT exist
// - Target allocator should work gracefully without errors

package main

import (
	"context"
	"fmt"
	"log/slog"
	"os"
	"time"

	monitoringv1 "github.com/prometheus-operator/prometheus-operator/pkg/apis/monitoring/v1"
	promv1alpha1 "github.com/prometheus-operator/prometheus-operator/pkg/apis/monitoring/v1alpha1"
	"github.com/prometheus-operator/prometheus-operator/pkg/assets"
	fakemonitoringclient "github.com/prometheus-operator/prometheus-operator/pkg/client/versioned/fake"
	"github.com/prometheus-operator/prometheus-operator/pkg/informers"
	"github.com/prometheus-operator/prometheus-operator/pkg/operator"
	"github.com/prometheus-operator/prometheus-operator/pkg/prometheus"
	prometheusgoclient "github.com/prometheus/client_golang/prometheus"
	v1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes/fake"
	"k8s.io/client-go/tools/cache"
	fcache "k8s.io/client-go/tools/cache/testing"

	allocatorconfig "github.com/open-telemetry/opentelemetry-operator/cmd/otel-allocator/internal/config"
	"github.com/open-telemetry/opentelemetry-operator/cmd/otel-allocator/internal/watcher"
)

func main() {
	logger := slog.New(slog.NewTextHandler(os.Stdout, &slog.HandlerOptions{Level: slog.LevelInfo}))
	slog.SetDefault(logger)

	fmt.Println("=== Testing Missing CRDs Scenario ===")
	fmt.Println("Scenario: ServiceMonitor and PodMonitor exist, but Probe and ScrapeConfig don't")
	fmt.Println()

	// Create test resources
	namespace := "test"
	serviceMonitor := &monitoringv1.ServiceMonitor{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-sm",
			Namespace: namespace,
		},
		Spec: monitoringv1.ServiceMonitorSpec{
			JobLabel: "test",
			Endpoints: []monitoringv1.Endpoint{
				{
					Port: "web",
				},
			},
		},
	}

	podMonitor := &monitoringv1.PodMonitor{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-pm",
			Namespace: namespace,
		},
		Spec: monitoringv1.PodMonitorSpec{
			JobLabel: "test",
			PodMetricsEndpoints: []monitoringv1.PodMetricsEndpoint{
				{
					Port: func() *string { s := "web"; return &s }(),
				},
			},
		},
	}

	// Create fake monitoring client and add resources
	mClient := fakemonitoringclient.NewSimpleClientset()
	_, err := mClient.MonitoringV1().ServiceMonitors(namespace).Create(context.Background(), serviceMonitor, metav1.CreateOptions{})
	if err != nil {
		logger.Error("Failed to create ServiceMonitor", "error", err)
		os.Exit(1)
	}
	logger.Info("Created ServiceMonitor", "name", serviceMonitor.Name)

	_, err = mClient.MonitoringV1().PodMonitors(namespace).Create(context.Background(), podMonitor, metav1.CreateOptions{})
	if err != nil {
		logger.Error("Failed to create PodMonitor", "error", err)
		os.Exit(1)
	}
	logger.Info("Created PodMonitor", "name", podMonitor.Name)

	// Create kubernetes client
	k8sClient := fake.NewSimpleClientset()

	// Create config
	cfg := allocatorconfig.Config{
		CollectorNamespace: namespace,
		PrometheusCR: allocatorconfig.PrometheusCRConfig{
			ServiceMonitorSelector:          &metav1.LabelSelector{},
			PodMonitorSelector:              &metav1.LabelSelector{},
			ProbeSelector:                   &metav1.LabelSelector{},
			ScrapeConfigSelector:            &metav1.LabelSelector{},
			ServiceMonitorNamespaceSelector: &metav1.LabelSelector{},
			PodMonitorNamespaceSelector:     &metav1.LabelSelector{},
			ProbeNamespaceSelector:          &metav1.LabelSelector{},
			ScrapeConfigNamespaceSelector:   &metav1.LabelSelector{},
		},
	}

	// Create factory
	factory := informers.NewMonitoringInformerFactories(
		map[string]struct{}{v1.NamespaceAll: {}},
		map[string]struct{}{},
		mClient,
		0,
		nil,
	)

	// Create informers - this should handle missing CRDs gracefully
	logger.Info("Creating informers (some CRDs may not exist)...")
	informerMap, err := watcher.GetInformers(factory)
	if err != nil {
		logger.Error("Failed to create informers", "error", err)
		os.Exit(1)
	}
	logger.Info("Successfully created informers", "count", len(informerMap))

	// List which informers were created
	for name := range informerMap {
		logger.Info("Informer created", "resource", name)
	}

	// Create prometheus CR
	serviceDiscoveryRole := monitoringv1.ServiceDiscoveryRole("EndpointSlice")
	prom := &monitoringv1.Prometheus{
		ObjectMeta: metav1.ObjectMeta{
			Namespace: namespace,
		},
		Spec: monitoringv1.PrometheusSpec{
			CommonPrometheusFields: monitoringv1.CommonPrometheusFields{
				ScrapeInterval:                  monitoringv1.Duration("30s"),
				ServiceMonitorSelector:          cfg.PrometheusCR.ServiceMonitorSelector,
				PodMonitorSelector:              cfg.PrometheusCR.PodMonitorSelector,
				ProbeSelector:                   cfg.PrometheusCR.ProbeSelector,
				ScrapeConfigSelector:            cfg.PrometheusCR.ScrapeConfigSelector,
				ServiceMonitorNamespaceSelector: cfg.PrometheusCR.ServiceMonitorNamespaceSelector,
				PodMonitorNamespaceSelector:     cfg.PrometheusCR.PodMonitorNamespaceSelector,
				ProbeNamespaceSelector:          cfg.PrometheusCR.ProbeNamespaceSelector,
				ScrapeConfigNamespaceSelector:   cfg.PrometheusCR.ScrapeConfigNamespaceSelector,
				ServiceDiscoveryRole:            &serviceDiscoveryRole,
				Version:                         "2.55.1",
			},
			EvaluationInterval: monitoringv1.Duration("30s"),
		},
	}

	promOperatorLogger := slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{Level: slog.LevelWarn}))
	generator, err := prometheus.NewConfigGenerator(promOperatorLogger, prom, prometheus.WithEndpointSliceSupport(), prometheus.WithInlineTLSConfig())
	if err != nil {
		logger.Error("Failed to create config generator", "error", err)
		os.Exit(1)
	}

	store := assets.NewStoreBuilder(k8sClient.CoreV1(), k8sClient.CoreV1())
	promRegisterer := prometheusgoclient.NewRegistry()
	operatorMetrics := operator.NewMetrics(promRegisterer)
	recorderFactory := operator.NewEventRecorderFactory(false)
	eventRecorder := recorderFactory(k8sClient, "target-allocator")

	source := fcache.NewFakeControllerSource()
	source.Add(&v1.Namespace{ObjectMeta: metav1.ObjectMeta{Name: namespace}})

	nsMonInf := cache.NewSharedInformer(source, &v1.Namespace{}, 1*time.Second).(cache.SharedIndexInformer)

	resourceSelector, err := prometheus.NewResourceSelector(promOperatorLogger, prom, store, nsMonInf, operatorMetrics, eventRecorder)
	if err != nil {
		logger.Error("Failed to create resource selector", "error", err)
		os.Exit(1)
	}

	// Create watcher
	w := &watcher.PrometheusCRWatcher{
		Logger:                          logger,
		KubeMonitoringClient:            mClient,
		K8sClient:                       k8sClient,
		Informers:                       informerMap,
		NsInformer:                      nsMonInf,
		StopChannel:                     make(chan struct{}),
		ConfigGenerator:                 generator,
		PodMonitorNamespaceSelector:     cfg.PrometheusCR.PodMonitorNamespaceSelector,
		ServiceMonitorNamespaceSelector: cfg.PrometheusCR.ServiceMonitorNamespaceSelector,
		ProbeNamespaceSelector:          cfg.PrometheusCR.ProbeNamespaceSelector,
		ScrapeConfigNamespaceSelector:   cfg.PrometheusCR.ScrapeConfigNamespaceSelector,
		ResourceSelector:                resourceSelector,
		Store:                           store,
		PrometheusCR:                    prom,
	}

	// Start informers
	logger.Info("Starting informers...")
	go nsMonInf.Run(w.StopChannel)
	for !nsMonInf.HasSynced() {
		time.Sleep(50 * time.Millisecond)
	}

	for name, informer := range informerMap {
		informer.Start(w.StopChannel)
		logger.Info("Started informer", "resource", name)
	}

	// Wait for informers to sync
	for name, informer := range informerMap {
		for !informer.HasSynced() {
			time.Sleep(50 * time.Millisecond)
		}
		logger.Info("Informer synced", "resource", name)
	}

	// Load config - this should work even with missing CRDs
	logger.Info("Loading configuration...")
	config, err := w.LoadConfig(context.Background())
	if err != nil {
		logger.Error("Failed to load config", "error", err)
		os.Exit(1)
	}

	logger.Info("Configuration loaded successfully", "scrape_configs", len(config.ScrapeConfigs))

	// Verify we have scrape configs from available CRDs
	if len(config.ScrapeConfigs) < 2 {
		logger.Error("Expected at least 2 scrape configs (from ServiceMonitor and PodMonitor)", "got", len(config.ScrapeConfigs))
		os.Exit(1)
	}

	for _, sc := range config.ScrapeConfigs {
		logger.Info("Scrape config", "job_name", sc.JobName)
	}

	// Clean up
	close(w.StopChannel)

	fmt.Println()
	fmt.Println("=== Test PASSED ===")
	fmt.Println("The target allocator handled missing CRDs gracefully:")
	fmt.Println("- No errors about missing Probe or ScrapeConfig CRDs")
	fmt.Println("- Successfully loaded configs from available ServiceMonitor and PodMonitor CRDs")
	fmt.Println("- The system continued to work without the missing CRDs")
}

